# High level events that make up HTTP/1.1 conversations. Loosely inspired by
# the corresponding events in hyper-h2:
#
#     http://python-hyper.org/h2/en/stable/api.html#events
#
# Don't subclass these. Stuff will break.

import re
from abc import ABC
from dataclasses import dataclass
from typing import List, Tuple, Union, Optional

from ._abnf import method, request_target
from ._headers import Headers, normalize_and_validate
from ._util import bytesify, LocalProtocolError, validate

# Everything in __all__ gets re-exported as part of the h11 public API.
__all__ = [
    "Event",
    "Request",
    "InformationalResponse",
    "Response",
    "Data",
    "EndOfMessage",
    "ConnectionClosed",
]

method_re = re.compile(method.encode("ascii"))
request_target_re = re.compile(request_target.encode("ascii"))


class Event(ABC):
    """
    Base class for h11 events.
    """

    __slots__ = ()


@dataclass(init=False, frozen=True)
class Request(Event):
    """The beginning of an HTTP request.

    Fields:

    .. attribute:: method

       An HTTP method, e.g. ``b"GET"`` or ``b"POST"``. Always a byte
       string. :term:`Bytes-like objects <bytes-like object>` and native
       strings containing only ascii characters will be automatically
       converted to byte strings.

    .. attribute:: target

       The target of an HTTP request, e.g. ``b"/index.html"``, or one of the
       more exotic formats described in `RFC 7320, section 5.3
       <https://tools.ietf.org/html/rfc7230#section-5.3>`_. Always a byte
       string. :term:`Bytes-like objects <bytes-like object>` and native
       strings containing only ascii characters will be automatically
       converted to byte strings.

    .. attribute:: headers

       Request headers, represented as a list of (name, value) pairs. See
       :ref:`the header normalization rules <headers-format>` for details.

    .. attribute:: http_version

       The HTTP protocol version, represented as a byte string like
       ``b"1.1"``. See :ref:`the HTTP version normalization rules
       <http_version-format>` for details.

    """

    __slots__ = ("method", "headers", "target", "http_version")

    method: bytes
    headers: Headers
    target: bytes
    http_version: bytes

    def __init__(
        self,
        *,
        method: Union[bytes, str],
        headers: Union[Headers, List[Tuple[bytes, bytes]], List[Tuple[str, str]]],
        target: Union[bytes, str],
        http_version: Union[bytes, str] = b"1.1",
        _parsed: bool = False,
    ) -> None:
        """Create a Request event with normalized headers, method, target and HTTP version.

        Parameters are bytes or ascii-only strings and will be converted to bytes
        unless _parsed is True (internal use).
        """
        super().__init__()
        if isinstance(headers, Headers):
            object.__setattr__(self, "headers", headers)
        else:
            object.__setattr__(
                self, "headers", normalize_and_validate(headers, _parsed=_parsed)
            )
        if not _parsed:
            object.__setattr__(self, "method", bytesify(method))
            object.__setattr__(self, "target", bytesify(target))
            object.__setattr__(self, "http_version", bytesify(http_version))
        else:
            object.__setattr__(self, "method", method)
            object.__setattr__(self, "target", target)
            object.__setattr__(self, "http_version", http_version)

        # "A server MUST respond with a 400 (Bad Request) status code to any
        # HTTP/1.1 request message that lacks a Host header field and to any
        # request message that contains more than one Host header field or a
        # Host header field with an invalid field-value."
        # -- https://tools.ietf.org/html/rfc7230#section-5.4
        host_count = 0
        for name, value in self.headers:
            if name == b"host":
                host_count += 1
        if self.http_version == b"1.1" and host_count == 0:
            raise LocalProtocolError("Missing mandatory Host: header")
        if host_count > 1:
            raise LocalProtocolError("Found multiple Host: headers")

        validate(method_re, self.method, "Illegal method character")
        validate(request_target_re, self.target, "Illegal request-target")


@dataclass(init=False, frozen=True)
class InformationalResponse(Event):
    """A 1xx informational HTTP response.

    Fields:

    .. attribute:: status_code

       An integer status code in the range 100-199.

    .. attribute:: headers

       Response headers, represented as a list of (name, value) pairs. See
       :ref:`the header normalization rules <headers-format>` for details.

    .. attribute:: http_version

       The HTTP protocol version, represented as a byte string like
       ``b"1.1"``.
    """

    __slots__ = ("status_code", "headers", "http_version")

    status_code: int
    headers: Headers
    http_version: bytes

    def __init__(
        self,
        *,
        status_code: int,
        headers: Union[Headers, List[Tuple[bytes, bytes]], List[Tuple[str, str]]],
        http_version: Union[bytes, str] = b"1.1",
        _parsed: bool = False,
    ) -> None:
        """Create an InformationalResponse event ensuring headers and status are valid.

        Parameters may be native strings or bytes; _parsed indicates internal use.
        """
        super().__init__()
        if isinstance(headers, Headers):
            object.__setattr__(self, "headers", headers)
        else:
            object.__setattr__(
                self, "headers", normalize_and_validate(headers, _parsed=_parsed)
            )
        object.__setattr__(self, "status_code", int(status_code))
        if not _parsed:
            object.__setattr__(self, "http_version", bytesify(http_version))
        else:
            object.__setattr__(self, "http_version", http_version)

        if not (100 <= self.status_code <= 199):
            raise LocalProtocolError(
                "InformationalResponse status codes must be in the range 100-199"
            )


@dataclass(init=False, frozen=True)
class Response(Event):
    """A non-informational HTTP response.

    Fields:

    .. attribute:: status_code

       An integer status code >= 200 and < 600.

    .. attribute:: headers

       Response headers, represented as a list of (name, value) pairs.

    .. attribute:: http_version

       The HTTP protocol version, represented as a byte string like ``b"1.1"``.

    .. attribute:: reason

       Optional reason phrase as a byte string. May be empty.
    """

    __slots__ = ("status_code", "headers", "http_version", "reason")

    status_code: int
    headers: Headers
    http_version: bytes
    reason: bytes

    def __init__(
        self,
        *,
        status_code: int,
        headers: Union[Headers, List[Tuple[bytes, bytes]], List[Tuple[str, str]]],
        http_version: Union[bytes, str] = b"1.1",
        reason: Union[bytes, str] = b"",
        _parsed: bool = False,
    ) -> None:
        """Create a Response event. Validates status code and normalizes headers.

        Bytes or ascii-only strings are accepted for parameters; use _parsed for internal creation.
        """
        super().__init__()
        if isinstance(headers, Headers):
            object.__setattr__(self, "headers", headers)
        else:
            object.__setattr__(
                self, "headers", normalize_and_validate(headers, _parsed=_parsed)
            )
        object.__setattr__(self, "status_code", int(status_code))
        if not _parsed:
            object.__setattr__(self, "http_version", bytesify(http_version))
            object.__setattr__(self, "reason", bytesify(reason))
        else:
            object.__setattr__(self, "http_version", http_version)
            object.__setattr__(self, "reason", reason)

        if 100 <= self.status_code <= 199:
            raise LocalProtocolError(
                "Response status codes must not be informational (100-199)"
            )
        if not (100 <= self.status_code <= 599):
            raise LocalProtocolError("Invalid status code")


@dataclass(init=False, frozen=True)
class Data(Event):
    """A chunk of message body data.

    Fields:

    .. attribute:: data

       A byte string containing part or all of the message body.
    """

    __slots__ = ("data",)

    data: bytes

    def __init__(self, *, data: Union[bytes, str], _parsed: bool = False) -> None:
        """Create a Data event; converts the input to bytes unless _parsed is True."""
        super().__init__()
        if not _parsed:
            object.__setattr__(self, "data", bytesify(data))
        else:
            object.__setattr__(self, "data", data)


@dataclass(init=False, frozen=True)
class EndOfMessage(Event):
    """Marks the end of the message. May carry optional trailer headers.

    Fields:

    .. attribute:: headers

       Trailer headers as a list of (name, value) pairs.
    """

    __slots__ = ("headers",)

    headers: Headers

    def __init__(
        self,
        *,
        headers: Optional[
            Union[Headers, List[Tuple[bytes, bytes]], List[Tuple[str, str]]]
        ] = None,
        _parsed: bool = False,
    ) -> None:
        """Create an EndOfMessage event. Normalize any provided trailer headers."""
        super().__init__()
        if headers is None:
            object.__setattr__(self, "headers", Headers([]))
        elif isinstance(headers, Headers):
            object.__setattr__(self, "headers", headers)
        else:
            object.__setattr__(
                self, "headers", normalize_and_validate(headers, _parsed=_parsed)
            )


class ConnectionClosed(Event):
    """Sent when the connection is closed unexpectedly."""

    __slots__ = ()

    def __init__(self) -> None:
        """Create a ConnectionClosed event (no attributes)."""
        super().__init__()